+inline __device__ float2 loadfloat2(void const* ptr) {
+  float2 return_value;
+  asm volatile("ld.volatile.global.v2.f32 {%0, %1}, [%2];\n"
+               : "=f"(return_value.x), "=f"(return_value.y)
+               : "l"(ptr));
+  return return_value;
+}
+
+template <typename T>
+inline __device__ T divUp(T val, T divisor) {
+  return (val + divisor - 1) / divisor;
+}
